VALUES
  ('tellimine', 'Tellimine', NULL, '<P>Tänapäeva raamatuid saab nüüdsest tellida interneti kaudu Apollost! Iga raamatu tutvustuse juures on nupp "Telli see raamat", mis suunab teid Apollo kodulehele sama raamatu juurde. </P>\r\n<P>Tellimise tingimusi loe <A href="http://www.apollo.ee/help#kuidas-registreerida">siit</A></P>', NULL, '2016-04-22T12:14:34+00'::timestamptz, NULL, NULL, true),
  ('lastekaitse-liit-valis-2012-a-parimad-lasteraamatud', 'Lastekaitse Liit valis 2012. a parimad lasteraamatud', NULL, '<p>MTÜ Lastekaitse Liidu eestvedamisel valiti 2012. aastal ilmunud uudiskirjanduse hulgast parimad lasteraamatud. Hea Raamatu märgi said ka kaks Tänapäeva lasteraamatut: <br>Aino Perviku <a href="https://tnp.ee/raamat?id=1234">Klabautermanni mure</a> <br>Piret Raua <a href="https://tnp.ee/raamat?id=1224">Natuke napakad lood</a><br>Õnne autoritele! <br>Oleme osaks saanud aule tänulikud ja rõõmsad! </p><p align="center"><img width="29" height="30" style="width: 88px; height: 89px;" src="/images/Hea Raamat logo.jpg"><div align="left"> </div></p>', NULL, '2016-04-22T12:14:32+00'::timestamptz, NULL, NULL, true),
  ('balti-raamatumess', 'Balti Raamatumess', NULL, '<P>Balti Raamatumess toimub Saku Suurhallis 13.-15. maini. Täpsem info aadressil <A href="http://www.estbook.com/">http://www.estbook.com/</A></P>\r\n<P>Tere tulemast Tänapäeva boksi!</P>', NULL, '2004-03-17T09:25:48+00'::timestamptz, NULL, NULL, true),
