  ('kommenteerige-meie-raamatuid', 'Kommenteerige meie raamatuid!', NULL, 'Meie uuel kodulehel on võimalik kõiki Tänapäeva raamatuid kommenteerida ja hinnata!', NULL, '2016-04-22T12:14:34+00'::timestamptz, NULL, NULL, true),
  ('pressiteade', 'Pressiteade', NULL, '<P class=MsoNormal style="MARGIN: 0in 0in 0pt; TEXT-ALIGN: right" align=right>\r\n<P class=MsoNormal style="MARGIN: 0in 0in 0pt; TEXT-ALIGN: right" align=right><SPAN lang=ET><FONT size=3><FONT face="Times New Roman"><?xml:namespace prefix = o ns = "urn:schemas-microsoft-com:office:office" /></FONT></FONT></SPAN></P>\r\n\r\n<P class=MsoNormal style="MARGIN: 0in 0in 0pt; LINE-HEIGHT: 150%"><SPAN lang=ET><FONT face="Times New Roman" size=3>Lastejuttude võistlusele laekus 60 käsikirja</FONT></SPAN></P>\r\n<P class=MsoNormal style="MARGIN: 0in 0in 0pt; LINE-HEIGHT: 150%"><SPAN lang=ET><FONT size=3><FONT face="Times New Roman"> </FONT></FONT></SPAN></P><SPAN lang=ET style="FONT-SIZE: 12pt; FONT-FAMILY: ''Times New Roman''; mso-fareast-font-family: ''Times New Roman''; mso-ansi-language: ET; mso-fareast-language: EN-US; mso-bidi-language: AR-SA">Eesti Lastekirjanduse Teabekeskus, kirjastus Tänapäev ja ajakiri Täheke kuulutasid möödunud aasta novembris välja algupäraste lastejuttude võistluse sarja “Minu esimene raamat” tarvis, kuhu oodati jutte 5-8 aasta vanustele lastele. Tööde esitamise tähtaeg oli 2. aprill 2004. Seekordne osavõtt ületas korraldajate julgemadki lootused – konkursile laekus tervelt 60 käsikirja. Planeeritud auhinnafond on 35 000 krooni, kavas on välja anda kolm põhiauhinda. Võistluse žürii teeb oma otsuse teatavaks 1. juunil, lastekaitsepäeval.</SPAN>', NULL, '2004-04-05T11:47:17+00'::timestamptz, NULL, NULL, true),
  ('jutuvoistluse-tulemused', 'Jutuvõistluse tulemused', NULL, '<H1 style="MARGIN: 0in 0in 0pt"><SPAN lang=ET><FONT face="Times New Roman" size=3>Jutuvõistluse “Minu esimene raamat” tulemused on selgunud</FONT></SPAN></H1>\r\n<P class=MsoNormal style="MARGIN: 0in 0in 0pt"><SPAN lang=ET style="mso-ansi-language: ET"><FONT size=3><FONT face="Times New Roman"> <?xml:namespace prefix = o ns = "urn:schemas-microsoft-com:office:office" /></FONT></FONT></SPAN></P>\r\n<P class=MsoNormal style="MARGIN: 0in 0in 0pt"><SPAN lang=ET style="mso-ansi-language: ET"><FONT size=3><FONT face="Times New Roman">Eesti Lastekirjanduse Teabekeskuse, kirjastuse Tänapäev ja ajakirja Täheke poolt korraldatud lastejuttude võistlusele “Minu esimene raamat” saabus kokku 61 tööd.</FONT></FONT></SPAN></P>\r\n<P class=MsoNormal style="MARGIN: 0in 0in 0pt"><SPAN lang=ET style="mso-ansi-language: ET"><FONT size=3><FONT face="Times New Roman">Žürii, mille kooseisu kuuluvad võistluse läbiviijate esindajad, tegid tulemused teatavaks 1. juunil 2004. </FONT></FONT></SPAN></P>\r\n<P class=MsoNormal style="MARGIN: 0in 0in 0pt"><SPAN lang=ET style="mso-ansi-language: ET"><FONT size=3><FONT face="Times New Roman">Tulemused.</FONT></FONT></SPAN></P>\r\n<P class=MsoNormal style="MARGIN: 0in 0in 0pt"><SPAN lang=ET style="mso-ansi-language: ET"><FONT size=3><FONT face="Times New Roman">I koht (16 000 krooni) “Ernesto küülikud”, Piret Raud</FONT></FONT></SPAN></P>\r\n<P class=MsoNormal style="MARGIN: 0in 0in 0pt"><SPAN lang=ET style="mso-ansi-language: ET"><FONT size=3><FONT face="Times New Roman">II koht (10 000 krooni) “Väike rüütel Rikardo”, Henno Käo</FONT></FONT></SPAN></P>\r\n<P class=MsoNormal style="MARGIN: 0in 0in 0pt"><SPAN lang=ET style="mso-ansi-language: ET"><FONT size=3><FONT face="Times New Roman">III koht (7000 krooni) “Veli Oliver”, Reet Made</FONT></FONT></SPAN></P>\r\n<P class=MsoNormal style="MARGIN: 0in 0in 0pt"><SPAN lang=ET style="mso-ansi-language: ET"><FONT size=3><FONT face="Times New Roman">III koht (7000 krooni) “Kasper, Amaalia-tädi ja tema viis tarka kassi”, Kristiina Kass</FONT></FONT></SPAN></P>\r\n<P class=MsoNormal style="MARGIN: 0in 0in 0pt"><SPAN lang=ET style="mso-ansi-language: ET"><FONT size=3><FONT face="Times New Roman">Ära märgitud:</FONT></FONT></SPAN></P>\r\n<P class=MsoNormal style="MARGIN: 0in 0in 0pt"><SPAN lang=ET style="mso-ansi-language: ET"><FONT size=3><FONT face="Times New Roman">“Talvine koolitee”, Jaanus Vaiksoo</FONT></FONT></SPAN></P>\r\n<P class=MsoNormal style="MARGIN: 0in 0in 0pt"><SPAN lang=ET style="mso-ansi-language: ET"><FONT size=3><FONT face="Times New Roman">“Koeralaps Berta seiklused”, Ketlin Priilinn</FONT></FONT></SPAN></P>\r\n<P><SPAN lang=EN-GB style="FONT-SIZE: 12pt; FONT-FAMILY: ''Times New Roman''; mso-ansi-language: EN-GB; mso-fareast-font-family: ''Times New Roman''; mso-fareast-language: EN-US; mso-bidi-language: AR-SA">Võistluse läbiviimist ja võidutööde avaldamist toetas Kultuuriministeerium. Võidutööd avaldab Tänapäev oma uuenenud lasteraamatusarjas ”Minu esimene raamat”.</SPAN></P>\r\n<P><A href="http://www.postimees.ee/020604/esileht/kultuur/135923.php">Loe uudist ajalehest Postimees</A></P>\r\n<P><A href="http://www.epl.ee/artikkel_266817.html">Uudis Eesti Päevalehes</A></P>\r\n<P><A href="http://www.epl.ee/artikkel_267080.html">Ilona Martsoni artikkel Eesti Päevalehes</A></P>', NULL, '2004-06-02T07:29:24+00'::timestamptz, NULL, NULL, true),
  ('auhinnad-kusitlusele-vastanutele', 'Auhinnad küsitlusele vastanutele', NULL, '<P>Tänapäeva ajalehes nr. 10 ilmunud küsitlusele saabus 63 vastust, neist 53 õiget. Õigesti vastanute vahel loosisime välja auhinnad:</P>\r\n<P><SPAN lang=ET style="mso-ansi-language: ET"><FONT size=3><FONT face="Times New Roman">PILLE HALLOP Võrust – “Eesti rahva elulood” I-III osa<?xml:namespace prefix = o ns = "urn:schemas-microsoft-com:office:office" /></FONT></FONT></SPAN></P>\r\n<P><SPAN lang=ET style="mso-ansi-language: ET"><FONT size=3><FONT face="Times New Roman">KAIA RIISMAA Pärnust – “Guinnessi maailmarekordid 2004”</FONT></FONT></SPAN></P>\r\n<P><SPAN lang=ET style="mso-ansi-language: ET"><FONT size=3><FONT face="Times New Roman">EVI TAMM Avinurmest – “Kõrgem kunstikool “Pallas””</FONT></FONT></SPAN></P>\r\n<P><SPAN lang=ET style="mso-ansi-language: ET"><FONT size=3><FONT face="Times New Roman">GUNNAR KAASIK Tallinnast – “Elu jõud. Tuntud eestlaste elulood”</FONT></FONT></SPAN></P>\r\n<P><SPAN lang=ET style="mso-ansi-language: ET"><FONT size=3><FONT face="Times New Roman">LIISI LINAMAA Tallinnast– “Eesti ballaad”</FONT></FONT></SPAN></P>\r\n<P><SPAN lang=ET style="mso-ansi-language: ET"><FONT size=3><FONT face="Times New Roman">PEEP PÄRNA Pärnust – “Eesti raudteejaamad”</FONT></FONT></SPAN></P>\r\n<P>\r\n<P>Võitjatega võtame ühendust. Täname kõiki vastajaid!</P>', NULL, '2004-06-03T07:08:43+00'::timestamptz, NULL, NULL, true),
  ('eestisse-tuleb-saksa-kirjanik-thomas-brussig', 'Eestisse tuleb saksa kirjanik Thomas Brussig', NULL, '<SPAN>\r\n<P class=MsoNormal style="MARGIN: 0cm 0cm 0pt"><FONT size=2><FONT size=4></FONT></FONT> </P>\r\n<P class=MsoNormal style="MARGIN: 0cm 0cm 0pt"><FONT size=2><STRONG><FONT size=3>14.09.2004 kell 19.00, Tallinna Linnarhiivi saalis, Tolli 4</FONT></STRONG></FONT></P>\r\n<P class=MsoNormal style="MARGIN: 0cm 0cm 0pt"><FONT size=2><STRONG></STRONG></FONT> </P>\r\n<P class=MsoNormal style="MARGIN: 0cm 0cm 0pt"><FONT size=2><STRONG><FONT size=3>Ettelugemine kestab üks tund ning on saksa keeles. (ilma tõlketa)</FONT></STRONG></FONT></P>\r\n<P class=MsoNormal style="MARGIN: 0cm 0cm 0pt"><FONT size=2><STRONG><FONT size=3>sissepääs vaba</FONT></STRONG></FONT></P>\r\n<P class=MsoNormal style="MARGIN: 0cm 0cm 0pt"><FONT size=2></FONT> </P>\r\n<P class=MsoNormal style="MARGIN: 0cm 0cm 0pt"><FONT size=2><FONT size=3><STRONG>Thomas Brussig</STRONG> on üks tänapäeva edukamaid ning tuntumaid kirjanikke Saksamaal. Ja seda mitte ainult tänu oma raamatutele; ka tema teoste ekraniseeringud on leidnud oma publiku. Eestis viibimise põhjuseks on aga tema kirjastuses "Tänapäev" äsja ilmunud romaan "Kangelased nagu meie" ("Helden wie wir")</FONT></FONT></P>\r\n<P class=MsoNormal style="MARGIN: 0cm 0cm 0pt"><FONT size=2></FONT> </P>\r\n<P class=MsoNormal style="MARGIN: 0cm 0cm 0pt"><FONT size=2><FONT size=3>Tallinnas loeb Thomas Brussig katkendeid raamatust "Am kürzeren Ende der Sonnenallee". Selles on humoorikal viisil kirjeldatud DDRi aegse Berliini noorte elu. Eriti tähtsat ja teinekord ka traagilist rolli mängisid suhted läänesakslastega, kes elasid sealsamas müüri taga, tänava teises otsas. See on lugu kadedusest, pilkamisest, põgenemisest, mustast ärist, narkootikumidest, esimesest armastusest. </FONT></FONT></P>\r\n<P class=MsoNormal style="MARGIN: 0cm 0cm 0pt"><FONT size=2></FONT> </P>\r\n<P class=MsoNormal style="MARGIN: 0cm 0cm 0pt"><FONT size=2><FONT size=3>Tallinna Saksa Kultuuriinstituudil/Goethe Instituudil ja kirjastusel "Tänapäev" on rõõm Teiega kohtuda Tallinna Linnaarhiivi saalis ettelugemisel, klaasikese veini juures. </FONT></FONT></P>\r\n<P class=MsoNormal style="MARGIN: 0cm 0cm 0pt"><FONT size=2></FONT> </P>\r\n<P class=MsoNormal style="MARGIN: 0cm 0cm 0pt"><FONT size=2><STRONG><FONT size=3>Kolmapäeval (15.09), kell 19.00 esineb Thomas Brussig </FONT></STRONG><A href="http://www.dki.tartu.ee/eesti.php" target=_blank><STRONG><FONT size=3>Tartu Saksa Kultuuri Instituudis,</FONT></STRONG></A><STRONG><FONT size=3> Kastani 1</FONT></STRONG></FONT></P></SPAN>', NULL, '2004-09-08T11:01:07+00'::timestamptz, NULL, NULL, true),
  ('varske-tanapaeva-leht-ilmunud', 'Värske Tänapäeva leht ilmunud', NULL, '23. septembril Postimehe vahel ilmus järjekordne Tänapäeva ajaleht, milles huvitavat lugemist meie ilmuvatest raamatutest ja äsjastest tegemistest. Lehte saab lugeda ka <A href="https://tnp.ee/ajaleht">siit</A>', NULL, '2004-12-02T10:53:33+00'::timestamptz, NULL, NULL, true),
  ('kirjastusel-tanapaev-on-frankfurdi-raamatumessil-oma-boks', 'Kirjastusel Tänapäev on Frankfurdi raamatumessil oma boks', NULL, '<P class=MsoNormal style="MARGIN: 0in 0in 0pt"><SPAN lang=ET style="mso-ansi-language: ET"><FONT size=3><FONT face="Times New Roman">Sel aastal on kirjastusel Tänapäev 6.–10. oktoobrini toimuval maailma suurimal raamatumessil Frankfurdis eraldi messiboks. Selle eraldasid Frankfurdi raamatumess ja Saksamaa Välisministeerium Tänapäevale kui Saksa kirjandust eesti keeles edukalt tutvustanud kirjastusele. Tänapäev asub messil hallis 6.0 boksis number C920. Samas hallis on ka Eesti Kirjastuste Liidu ja õpikukirjastuse Koolibri boksid. </FONT></FONT></SPAN></P>\r\n<P class=MsoNormal style="MARGIN: 0in 0in 0pt"><SPAN lang=ET style="mso-ansi-language: ET"><FONT size=3><FONT face="Times New Roman"></FONT></FONT></SPAN> </P>\r\n<P class=MsoNormal style="MARGIN: 0in 0in 0pt"><SPAN lang=ET style="mso-ansi-language: ET"><FONT size=3><FONT face="Times New Roman"><A href="http://www.frankfurt-book-fair.com/en/portal.php">Frankfurdi raamatumessi kodulehele</A></FONT></FONT></SPAN></P>', NULL, '2004-09-28T11:57:58+00'::timestamptz, NULL, NULL, true),
  ('kevadine-soodusmuuk', 'Kevadine soodusmüük', NULL, '<P>7. - 27. märtsini on raamatupoodides soodsa hinnaga </P>\r\n<P><A href="http://www.apollo.ee/product.php/0691620">Charles Bukowski. Pöörase elu rüpes 100.-</A></P>\r\n<P><A href="http://www.apollo.ee/product.php/0691670">Meistri ja Margarita päevik 149.-</A></P>\r\n<P><A href="http://www.apollo.ee/product.php/0691719">Punane draakon 100.-</A></P>\r\n<P><BR>Minu väga magus elu ehk martsipanimeister 20.-</P>\r\n<P><A href="http://www.apollo.ee/product.php/0691867">Catherine M-i seksuaalelu 99.-</A></P>\r\n<P><A href="http://www.apollo.ee/product.php/0691859">Argielu eliksiir 99.-</A></P>\r\n<P><A href="http://www.apollo.ee/product.php/0691557">Kolmekesi 10.-</A></P>\r\n<P><A href="http://www.apollo.ee/product.php/0691813">Ameerika jumalad 100.-</A></P>\r\n<P><A href="http://www.apollo.ee/product.php/0691891">Kes?Mis?Kus? 2004 49.-</A></P>\r\n<P><A href="http://www.apollo.ee/product.php/0691727">Visnapuu armastusest 49.-</A></P>\r\n<P><A href="http://www.apollo.ee/product.php/0691565">Appi, ma elan poisikesega 20.-</A></P>\r\n<P><A href="http://www.apollo.ee/product.php/0691280">Südamest räägitud lood 49.-</A></P>\r\n<P><A href="http://www.apollo.ee/product.php/0691484">Küüniku sõnaraamat 100.-</A></P>\r\n<P><A href="http://www.apollo.ee/product.php/0691950">Kõrgem kunstikool "Pallas" 199.-</A></P>\r\n<P><A href="http://www.apollo.ee/product.php/0692209">Ma armastasin venelast 49.-</A></P>\r\n<P><A href="http://www.apollo.ee/product.php/0692279">Paradiis ja jõud 19.-</A></P>', NULL, '2005-03-04T12:30:18+00'::timestamptz, NULL, NULL, true),
  ('kultuurkapitali-lastekirjanduse-aastapreemia', 'Kultuurkapitali lastekirjanduse aastapreemia', NULL, '<P>Kultuurkapitali lastekirjanduse aastapreemia võitis Jaan Rannapi "Nelja nimega koer"</P>\r\n<P><A href="http://www.postimees.ee/210305/esileht/kultuur/160638.php">Loe uudist Postimehest</A></P>', NULL, '2005-03-21T09:20:52+00'::timestamptz, NULL, NULL, true),
