  ('lastejutuvoistluse-tulemused', 'Lastejutuvõistluse tulemused', NULL, '<P>Eesti Lastekirjanduse Teabekeskuse, kirjastuse Tänapäev ja ajakirja Täheke lastejutuvõistlusele "Minu esimene raamat" laekus kokku 38 käsikirja.</P>\r\n<P>Auhinnad jagunesid:</P>\r\n<P>III koht, a 5000 krooni</P>\r\n<P>märgusõna "Ville", võistlustöö "Ville", Kätlin Vainola<BR>märgusõna "Urre Soio", võistlustöö "Apteegitont Aavi", Siiri Laidla<BR>märgusõna BiBaBo, "Notsu Norbert ja Tähetäpi mudaravila", Reet Palis</P>\r\n<P>II koht, a 10 000 krooni</P>\r\n<P>märgusõna "Margaret", võistlustöö "Kuninganna Anni lood", Marju Õunpuu<BR>märgusõna "Sinine lepatriinu", "Liivahiirte suur seiklus", Ingrid Gilts-Nittim</P>\r\n<P>I koht 20 000 krooni</P>\r\n<P>märgusõna "Seebimull", võistlustöö "Samueli võlupadi", Kristiina Kass-Nokelainen</P>', NULL, '2005-12-19T11:48:26+00'::timestamptz, NULL, NULL, true),
  ('ajaleht-raamat', 'Ajaleht Raamat', NULL, 'Eesti Kirjastuste Liidu ajaleht "Raamat" ilmus 8. detsembri Postimehe vahel. <A href="https://tnp.ee/download/ajaleht_low_res.pdf" target=_blank>Lehte saab lugeda siit.</A>', NULL, '2005-12-13T14:03:45+00'::timestamptz, NULL, NULL, true),
